import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { formatDistanceToNow, format } from 'date-fns';
import { getArticle } from '../utils/api';
import Navbar from '../components/Navbar';

function pillClass(cat) {
  const m = { Technology:'pill-tech', Politics:'pill-politics', Business:'pill-business', Sports:'pill-sports', Entertainment:'pill-entertainment', Science:'pill-science', Health:'pill-health', World:'pill-world' };
  return m[cat] || 'pill-default';
}

export default function ArticlePage() {
  const { id } = useParams();
  const [article, setArticle] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getArticle(id).then(r => setArticle(r.data.article)).catch(console.error).finally(() => setLoading(false));
  }, [id]);

  if (loading) return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: 300 }}>
        <div className="spinner" />
      </div>
    </div>
  );

  if (!article) return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div style={{ textAlign: 'center', padding: 80 }}>
        <div style={{ fontSize: 13, color: 'var(--text2)', marginBottom: 16 }}>Article not found</div>
        <Link to="/" className="btn btn-primary">← Back</Link>
      </div>
    </div>
  );

  const { title, summary, category, tags = [], sources = [], publishedAt, createdAt } = article;
  const timeAgo = (() => { try { return formatDistanceToNow(new Date(publishedAt || createdAt), { addSuffix: true }); } catch { return ''; } })();
  const dateStr = (() => { try { return format(new Date(publishedAt || createdAt), 'MMMM d, yyyy · h:mm a'); } catch { return ''; } })();

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div className="container" style={{ maxWidth: 780, paddingTop: 32, paddingBottom: 64 }}>
        <Link to="/" style={{ display: 'inline-flex', alignItems: 'center', gap: 6, color: 'var(--text2)', fontSize: 13, marginBottom: 24 }}>
          ← Back to news
        </Link>

        <article className="fade-in">
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 16, flexWrap: 'wrap' }}>
            <span className={`pill ${pillClass(category)}`}>{category}</span>
            {sources.length > 1 && <span className="multi-source">🔗 Covered by {sources.length} sources</span>}
          </div>

          <h1 style={{ fontFamily: 'var(--display)', fontSize: 'clamp(22px,4vw,34px)', fontWeight: 800, lineHeight: 1.25, marginBottom: 14 }}>
            {title}
          </h1>

          <div style={{ fontSize: 13, color: 'var(--text2)', marginBottom: 24 }}>{dateStr} · {timeAgo}</div>

          <div style={{ height: 1, background: 'var(--border)', marginBottom: 24 }} />

          {/* AI Summary box */}
          <div style={{ background: 'rgba(136,197,64,0.06)', border: '1px solid rgba(136,197,64,0.2)', borderRadius: 10, padding: 22, marginBottom: 28 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: 'var(--accent)', textTransform: 'uppercase', letterSpacing: '0.1em' }}>
                Description
              </span>
            </div>
            <p style={{ lineHeight: 1.7, color: 'var(--text)', fontSize: 15 }}>{summary}</p>
          </div>

          {/* Tags */}
          {tags.length > 0 && (
            <div style={{ marginBottom: 28 }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--text2)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 10 }}>Topics</div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {tags.map(t => (
                  <span key={t} style={{ padding: '4px 12px', background: 'var(--bg3)', border: '1px solid var(--border)', borderRadius: 20, fontSize: 12, color: 'var(--text2)' }}>#{t}</span>
                ))}
              </div>
            </div>
          )}

          {/* Sources */}
          <div style={{ background: 'var(--bg2)', border: '1px solid var(--border)', borderRadius: 10, padding: 20 }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--text2)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 14 }}>
              {sources.length > 1 ? `📡 ${sources.length} Sources Covering This Story` : '📡 Source'}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {sources.map((s, i) => (
                <a key={i} href={s.url} target="_blank" rel="noopener noreferrer" style={{
                  display: 'flex', alignItems: 'center', gap: 12,
                  padding: '12px 14px', background: 'var(--bg3)',
                  border: '1px solid var(--border)', borderRadius: 8,
                  color: 'var(--text)', transition: 'border-color 0.2s',
                }}
                  onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--accent)'}
                  onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--border)'}
                >
                  <div style={{ width: 32, height: 32, background: `hsl(${i*80},50%,25%)`, borderRadius: 6, display:'flex', alignItems:'center', justifyContent:'center', fontSize: 14, flexShrink: 0 }}>📰</div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{s.name}</div>
                    <div style={{ fontSize: 11, color: 'var(--text2)', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{s.url}</div>
                  </div>
                  <span style={{ fontSize: 11, color: 'var(--accent)', flexShrink: 0 }}>Read →</span>
                </a>
              ))}
            </div>
          </div>
        </article>
      </div>
    </div>
  );
}
